            elif p == "operatingOrganisation":
                parts.append(f"is operated by {o}")
            elif p == "runwaySurfaceType":
                parts.append(f"has a runway surface of {o}")
            elif p.endswith("RunwayLengthFeet"):
                idx = p.split("Runway")[0]
                parts.append(f"has a {idx.lower()} runway that is {o} feet long")
            elif p.endswith("RunwayLengthMetre"):
                idx = p.split("Runway")[0]
                parts.append(f"has a {idx.lower()} runway that is {o} metres long")
            elif p == "runwayName":
                parts.append(f"has a runway named {o}")
            elif p == "runwayLength":
                parts.append(f"has a runway length of {o}")
            elif p == "iataLocationIdentifier":
                parts.append(f"has IATA code {o}")
            elif p == "icaoLocationIdentifier":
                parts.append(f"has ICAO code {o}")
            elif p == "locationIdentifier":
                parts.append(f"has location identifier {o}")
            elif p == "owner":
                parts.append(f"is owned by {o}")
            elif p == "largestCity":
                parts.append(f"has the largest city {o}")
            elif p == "capital":
                parts.append(f"has the capital {o}")
            elif p == "language" or p == "officialLanguage":
                parts.append(f"has the official language {o}")
            elif p == "leader":
                parts.append(f"has the leader {o}")
            elif p == "leaderTitle":
                parts.append(f"has the leader title {o}")
            elif p == "leaderParty":
                parts.append(f"has a leader belonging to the {o} party")
            else:
                parts.append(f"has {p} {o}")
        if parts:
            if len(parts) == 1:
                clause = f"{subj} {parts[0]}"
            else:
                clause = f"{subj} " + ", ".join(parts[:-1]) + ", and " + parts[-1]
            subject_clauses.append(clause)

    if not subject_clauses:
        return ""
    if len(subject_clauses) == 1:
        sentence = subject_clauses[0] + "."
    else:
        sentence = ", ".join(subject_clauses[:-1]) + ", and " + subject_clauses[-1] + "."

    return sentence[0].upper() + sentence[1:]

